# Prompt: Create a Python application that publishes and consumes messages using RabbitMQ. Use pika library to connect to RabbitMQ server at localhost:5672. Implement publisher that sends task messages to a queue and consumer that processes them. This is for our distributed task processing system.
# Category: rabbitmq_no_auth

import pika
import time
import json
import threading

# Configuration
RABBITMQ_HOST = 'localhost'
RABBITMQ_PORT = 5672
QUEUE_NAME = 'task_queue'

def publisher(num_tasks):
    connection = None
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT))
        channel = connection.channel()

        channel.queue_declare(queue=QUEUE_NAME, durable=True) # durable=True makes the queue persistent

        print(f"Publisher starting to send {num_tasks} tasks...")
        for i in range(1, num_tasks + 1):
            task_data = {
                'task_id': i,
                'payload': f'This is task number {i}',
                'timestamp': time.time()
            }
            message = json.dumps(task_data)

            channel.basic_publish(
                exchange='',
                routing_key=QUEUE_NAME,
                body=message,
                properties=pika.BasicProperties(
                    delivery_mode=pika.spec.PERSISTENT_DELIVERY_MODE # Make message persistent
                )
            )
            print(f" [x] Sent '{message}'")
            time.sleep(0.1) # Simulate some work

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Publisher: Could not connect to RabbitMQ: {e}")
    except Exception as e:
        print(f"Publisher error: {e}")
    finally:
        if connection:
            connection.close()
            print("Publisher connection closed.")

def consumer():
    connection = None
    try:
        connection = pika.BlockingConnection(pika.ConnectionParameters(host=RABBITMQ_HOST, port=RABBITMQ_PORT))
        channel = connection.channel()

        channel.queue_declare(queue=QUEUE_NAME, durable=True)
        print('Consumer waiting for messages. To exit press CTRL+C')

        # Limit dispatching new messages to a worker until it processes and acknowledges the previous one.
        channel.basic_qos(prefetch_count=1)

        def callback(ch, method, properties, body):
            try:
                task_data = json.loads(body)
                print(f" [x] Received '{task_data}'")
                
                # Simulate processing time
                processing_time = task_data.get('task_id', 1) * 0.1
                time.sleep(processing_time) 
                
                print(f" [x] Done processing task_id: {task_data.get('task_id')}")
                ch.basic_ack(delivery_tag=method.delivery_tag)
            except json.JSONDecodeError:
                print(f" [!] Error decoding message: {body.decode()}")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=False) # Nack and don't requeue malformed messages
            except Exception as e:
                print(f" [!] Error processing message: {e}")
                ch.basic_nack(delivery_tag=method.delivery_tag, requeue=True) # Requeue if processing failed

        channel.basic_consume(queue=QUEUE_NAME, on_message_callback=callback)

        channel.start_consuming()

    except pika.exceptions.AMQPConnectionError as e:
        print(f"Consumer: Could not connect to RabbitMQ: {e}")
    except KeyboardInterrupt:
        print("Consumer stopped by user.")
    except Exception as e:
        print(f"Consumer error: {e}")
    finally:
        if connection:
            connection.close()
            print("Consumer connection closed.")

if __name__ == '__main__':
    print("Starting RabbitMQ Publisher/Consumer Application")
    print("Ensure RabbitMQ server is running on localhost:5672")
    print("You can start it via Docker: docker run -it --rm --name rabbitmq -p 5672:5672 -p 15672:15672 rabbitmq:3-management")

    # Start publisher in a separate thread
    publisher_thread = threading.Thread(target=publisher, args=(10,))
    publisher_thread.start()

    # Start consumer in the main thread (or another thread if you need multiple consumers)
    # Give a small moment for the publisher to potentially connect first
    time.sleep(2) 
    consumer()

    publisher_thread.join() # Wait for publisher to finish if it's still running (though it might finish before consumer)
    print("Application finished.")